%[text] ME5405 Machine Vision - Image 1: Chromosomes (chromo.txt)
%[text] This script performs all required image processing tasks on Image 1.
%[text] The image shows chromosomes (dark objects on a bright background).
close all; clear; clc;

addpath('src/lib');
data_dir    = './data/';
results_dir = './results/';
%[text] Task 1.1: Display the original image
% ----------------------------------------------------------
% 01 Display Original Image
% ----------------------------------------------------------

fprintf('=== Task 1.1: Display Original Image ===\n'); %[output:7919854d]

img = load_txt2img([data_dir 'chromo.txt']); %[output:623708cb]

figure('Name','[Task 1] Original Image'); %[output:5e3e1dd9]
imshow(img, 'DisplayRange', [min(img(:)) max(img(:))], 'InitialMagnification', 'fit'); %[output:5e3e1dd9]
title('Image 1: Chromosomes (Original)'); axis ('on', 'image'); colorbar; %[output:5e3e1dd9]
saveas(gcf,[results_dir 'img1_01_original.png']); %[output:5e3e1dd9]

figure('Name','[Task 1] Intensity Histogram'); %[output:9ed4f63f]
histogram(img, 'BinEdges', 0.5:1:32.5); %[output:9ed4f63f]
xlabel('Intensity Level'); %[output:9ed4f63f]
ylabel('Frequency'); %[output:9ed4f63f]
title('Image 1: Intensity Histogram'); %[output:9ed4f63f]
xlim([0 32]); %[output:9ed4f63f]
saveas(gcf,[results_dir 'img1_02_histogram.png']); %[output:9ed4f63f]
%[text] Task 1.2: Threshold into binary image
% ----------------------------------------------------------
% 02 Otsu Thresholding Binary Image
% ----------------------------------------------------------

fprintf('=== Task 1.2: Threshold Into Binary Image ===\n'); %[output:6007a318]

[T, threshold] = otsu_threshold(img); %[output:09d32660]

figure('Name','[Task 1] Thresholded Binary Image'); %[output:3ca5fb08]
imshow(T, 'InitialMagnification', 'fit') %[output:3ca5fb08]
title(sprintf('Image 1: Otsu Threshold k* = %d', threshold-1)); axis ('on', 'image'); %[output:3ca5fb08]
saveas(gcf,[results_dir 'img1_03_binarized.png']); %[output:3ca5fb08]
%[text] Task 1.3: One-pixel thin image (skeletonization)
% ----------------------------------------------------------
% 03 Zhang-Suen Thinning Skeletonized Image
% ----------------------------------------------------------

fprintf('=== Task 1.3: One-Pixel Thin Image Skeletonization ===\n'); %[output:5680f9d9]

thinned = zs_thinning(T, 0); %[output:04e5e055]

figure('Name','[Task 1] One-Pixel Thin Image'); %[output:47174dba]
imshow(thinned, 'InitialMagnification', 'fit'); %[output:47174dba]
title('Image 1: One-pixel Thin Image'); axis ('on', 'image'); %[output:47174dba]
saveas(gcf,[results_dir 'img1_04_skeletonized.png']); %[output:47174dba]
%[text] Task 1.4: Determine boundary outlines
% ----------------------------------------------------------
% 04 Outline Detection Boundary Image
% ----------------------------------------------------------

fprintf('=== Task 1.4: Determine Image Boundary Outlines ===\n'); %[output:211e15e8]

bound = boundary_detect(T, 0);

figure('Name','[Task 1] Outline Detection Image'); %[output:5bf65d46]
imshow(bound, 'InitialMagnification', 'fit') %[output:5bf65d46]
title('Image 1: Boundary Outline'); axis ('on', 'image'); %[output:5bf65d46]
saveas(gcf,[results_dir 'img1_05_outline.png']); %[output:5bf65d46]
%[text] Task 1.5: Label different objects
% ----------------------------------------------------------
% 05 Object Labeling Image Segmentation
% ----------------------------------------------------------

fprintf('=== Task 1.5: Segment Image and Label Objects ===\n'); %[output:4f1977d9]

[label_matrix, num_components] = ccl_segment(T, 0); %[output:93376346]

display_matrix = double(label_matrix);
display_matrix(label_matrix == 0) = NaN;

figure('Name','[Task 1] Segmented Object Labeling Image'); %[output:759d4412]
imagesc(display_matrix, 'AlphaData', ~isnan(display_matrix)); %[output:759d4412]
set(gca, 'Color', 'white'); colormap(jet); colorbar; %[output:759d4412]
title(sprintf('Image 1: Segmenting - %d regions found', num_components)); %[output:759d4412]
axis ('on', 'image'); %[output:759d4412]
saveas(gcf,[results_dir 'img1_06_segmenting.png']); %[output:759d4412]

